import React from 'react';
import styled from 'styled-components';

const Home = () => {
  return (
    <MainContainer>
      {/* Hero Section */}
      <HeroSection>
        <HeroImage src="/assets/hero.jpg" alt="Hero Plant" />
        <HeroText>
          <h1>Welcome to NatureNest 🌿</h1>
          <p>Your one-stop online plant nursery. Discover, shop, and learn plant care from the experts.</p>
          <button>Shop Now</button>
        </HeroText>
      </HeroSection>

      {/* About Us */}
      <AboutSection>
        <h2>About Us</h2>
        <p>
          At <strong>NatureNest</strong>, we are passionate about nurturing a greener, healthier lifestyle. Our journey began with a
          simple idea: making plant shopping and care accessible, enjoyable, and sustainable. Whether you're a beginner or a seasoned
          gardener, NatureNest offers a carefully curated selection of indoor, outdoor, and medicinal plants tailored to your needs.
          <br /><br />
          We collaborate with local nurseries and eco-conscious growers to ensure every plant is healthy, pesticide-free, and delivered with care.
          Beyond just selling plants, we aim to build a vibrant plant-lover community by offering expert tips, plant care calendars, and
          personalized support.
          <br /><br />
          By choosing NatureNest, you're not just buying a plant—you're joining a movement toward greener homes, mindful living, and environmental responsibility.
        </p>
      </AboutSection>

      {/* Featured Plants */}
      <FeaturedSection>
        <h2>Featured Plants</h2>
        <PlantGrid>
          {[
            {
              name: 'Snake Plant',
              image: '/assets/plant1.jpg',
              desc: 'Low-maintenance air-purifier perfect for bedrooms and offices.',
            },
            {
              name: 'Aloe Vera',
              image: '/assets/plant2.jpg',
              desc: 'Medicinal plant with soothing gel—great for skin care and burns.',
            },
            {
              name: 'Peace Lily',
              image: '/assets/plant3.jpg',
              desc: 'Elegant white blooms and natural air-purifying qualities.',
            },
            {
              name: 'Spider Plant',
              image: '/assets/plant4.jpg',
              desc: 'Fast-growing with cascading leaves—ideal for hanging baskets.',
            },
          ].map((plant, i) => (
            <PlantCard key={i}>
              <img src={plant.image} alt={plant.name} />
              <h3>{plant.name}</h3>
              <p>{plant.desc}</p>
            </PlantCard>
          ))}
        </PlantGrid>
      </FeaturedSection>
    </MainContainer>
  );
};

export default Home;

// Styled Components
const MainContainer = styled.div`
  font-family: 'Segoe UI', sans-serif;
`;

const HeroSection = styled.section`
  display: flex;
  align-items: center;
  padding: 40px;
  background-color: #f5fff5;
  @media (max-width: 768px) {
    flex-direction: column;
  }
`;

const HeroImage = styled.img`
  width: 50%;
  max-width: 500px;
  border-radius: 10px;
`;

const HeroText = styled.div`
  flex: 1;
  padding-left: 40px;

  h1 {
    color: #2e7d32;
    font-size: 2.5rem;
  }

  p {
    font-size: 1.2rem;
    margin: 20px 0;
  }

  button {
    background-color: #2e7d32;
    color: white;
    padding: 12px 24px;
    border: none;
    border-radius: 8px;
    font-size: 1rem;
    cursor: pointer;
    transition: background-color 0.3s;
  }

  button:hover {
    background-color: #1b5e20;
  }
`;

const AboutSection = styled.section`
  padding: 40px;
  text-align: center;
  background-color: #ffffff;

  h2 {
    font-size: 2rem;
    color: #2e7d32;
    margin-bottom: 20px;
  }

  p {
    max-width: 800px;
    margin: 0 auto;
    font-size: 1.1rem;
    line-height: 1.7;
  }
`;

const FeaturedSection = styled.section`
  padding: 40px;
  background-color: #f0fff0;
  text-align: center;

  h2 {
    font-size: 2rem;
    color: #2e7d32;
    margin-bottom: 30px;
  }
`;

const PlantGrid = styled.div`
  display: flex;
  gap: 20px;
  justify-content: center;
  flex-wrap: wrap;
`;

const PlantCard = styled.div`
  background-color: white;
  border-radius: 10px;
  padding: 20px;
  box-shadow: 0 0 15px rgba(0, 0, 0, 0.1);
  width: 220px;
  text-align: center;
  transition: transform 0.2s ease;

  &:hover {
    transform: scale(1.03);
  }

  img {
    width: 100%;
    height: 150px;
    object-fit: cover;
    border-radius: 8px;
    margin-bottom: 10px;
  }

  h3 {
    margin: 10px 0 5px;
    color: #2e7d32;
    font-size: 1.1rem;
  }

  p {
    font-size: 0.95rem;
    color: #555;
  }
`;
